package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetQuoteMode_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        QuoteMode quoteMode = format.getQuoteMode();
        assertNotNull(quoteMode);
    }

    @Test
    void testGetQuoteMode_CustomQuoteMode() {
        QuoteMode customQuoteMode = QuoteMode.ALL;
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(customQuoteMode);
        assertSame(customQuoteMode, format.getQuoteMode());
    }

    @Test
    void testGetQuoteMode_NullQuoteMode() {
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(null);
        assertNull(format.getQuoteMode());
    }
}
